sys_script_include.script:
var CheckinAjax = Class.create();
CheckinAjax.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {
	/**
	 * Created date   : 14/05/2026
	 * Author         : Quynhttn
	 * Function       : getCandidateInfomation
	 * Description    : Get candidate username and phone number
	 * Parameters     : sysparm_candidate_id
	 * Return         : JSON string containing candidate information
	 */
	getCandidateInfomation: function() {
		var candidateId = this.getParameter('sysparm_candidate_id'); // Get candidate sys_id

		// Initialize GlideRecord for Candidate table
		var grCandidate = new GlideRecord('x_1763182_talent_0_candidate');  
		var result = {};

		// Query candidate record by sys_id
		if(grCandidate.get(candidateId)){
			// Get candidate information
			result = {
				candidateUsername: grCandidate.getValue('u_username'),
				candidatePhonenumber: grCandidate.getValue('u_phone_number')
			};
		}
		return JSON.stringify(result);
	},
    type: 'CheckinAjax'
});
